package main

import (
	"fmt"
	"net/http"
	"regexp"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	validLabel = regexp.MustCompile(`^[a-zA-Z0-9_]+$`)
	userRequests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total number of requests per user.",
		},
		[]string{"username"},
	)
)

func init() {
	prometheus.MustRegister(userRequests)
}

func validateLabel(label string) bool {
	return validLabel.MatchString(label)
}

func requestHandler(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("username")

	if !validateLabel(username) {
		http.Error(w, "Invalid username", http.StatusBadRequest)
		return
	}

	userRequests.WithLabelValues(username).Inc()
	fmt.Fprintf(w, "Request recorded for user: %s", username)
}

func main() {
	http.Handle("/metrics", promhttp.Handler())
	http.HandleFunc("/request", requestHandler)

	fmt.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Println("Error starting server:", err)
	}
}